1	import { create } from "zustand";
2	import type {
3	  TrackModel,
4	  ClipModel,
5	  MidiClipModel,
6	  MIDINoteEvent,
7	} from "./track/types";
8	import { isAudioClip, isMidiClip } from "./track/types";
9	
10	export type TransportState = "stopped" | "playing" | "paused";
11	
12	export type AudioEngineStatus =
13	  | "uninitialized"
14	  | "suspended"
15	  | "running"
16	  | "error";
17	
18	export type DawStore = {
19	  // Transport
20	  transportState: TransportState;
21	  bpm: number;
22	  cursorSeconds: number;
23	  loopEnabled: boolean;
24	  loopStart: number;
25	  loopEnd: number;
26	
27	  // Audio engine
28	  engineStatus: AudioEngineStatus;
29	
30	  // Mixer
31	  masterVolume: number;
32	
33	  // Tracks & clips
34	  tracks: readonly TrackModel[];
35	  clips: Record<string, ClipModel>;
36	  selectedTrackIds: readonly string[];
37	  selectedClipIds: readonly string[];
38	  selectedNoteIds: readonly string[];
39	
40	  // Transport actions
41	  play: () => void;
42	  pause: () => void;
43	  stop: () => void;
44	  setBpm: (bpm: number) => void;
45	  setCursor: (seconds: number) => void;
46	  setLoop: (enabled: boolean, start?: number, end?: number) => void;
47	
48	  // Engine actions
49	  setEngineStatus: (status: AudioEngineStatus) => void;
50	
51	  // Mixer actions
52	  setMasterVolume: (volume: number) => void;
53	
54	  // Track actions
55	  addTrack: (track: TrackModel, index?: number) => void;
56	  removeTrack: (id: string) => void;
57	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => void;
58	  reorderTrack: (id: string, toIndex: number) => void;
59	
60	  // Clip actions
61	  addClip: (clip: ClipModel) => void;
62	  removeClip: (id: string) => void;
63	  moveClip: (id: string, startTime: number, toTrackId?: string) => void;
64	  splitClip: (
65	    id: string,
66	    atTime: number,
67	    providedId?: string,
68	  ) => string | undefined;
69	  trimClip: (id: string, newStart?: number, newEnd?: number) => void;
70	  duplicateClip: (id: string, providedId?: string) => string | undefined;
71	
72	  // MIDI clip actions
73	  addMidiClip: (clip: MidiClipModel) => void;
74	  removeMidiClip: (id: string) => void;
75	  addNoteEvent: (clipId: string, note: MIDINoteEvent) => void;
76	  removeNoteEvent: (clipId: string, noteId: string) => void;
77	  moveNoteEvent: (
78	    clipId: string,
79	    noteId: string,
80	    newStartTime: number,
81	    newPitch: number,
82	  ) => void;
83	  resizeNoteEvent: (
84	    clipId: string,
85	    noteId: string,
86	    newDuration: number,
87	  ) => void;
88	  updateNoteVelocity: (
89	    clipId: string,
90	    noteId: string,
91	    velocity: number,
92	  ) => void;
93	
94	  // Selection actions
95	  setSelectedTrackIds: (ids: readonly string[]) => void;
96	  setSelectedClipIds: (ids: readonly string[]) => void;
97	  setSelectedNoteIds: (ids: readonly string[]) => void;
98	
99	  // Query
100	  queryClipsAtTime: (time: number) => readonly ClipModel[];
101	};
102	
103	function nextClipId(): string {
104	  return "clip-" + crypto.randomUUID();
105	}
106	
107	export const useDawStore = create<DawStore>()((set, get) => ({
108	  // Transport defaults
109	  transportState: "stopped",
110	  bpm: 120,
111	  cursorSeconds: 0,
112	  loopEnabled: false,
113	  loopStart: 0,
114	  loopEnd: 0,
115	
116	  // Engine defaults
117	  engineStatus: "uninitialized",
118	
119	  // Mixer defaults
120	  masterVolume: 1,
121	
122	  // Track & clip defaults
123	  tracks: [],
124	  clips: {},
125	  selectedTrackIds: [],
126	  selectedClipIds: [],
127	  selectedNoteIds: [],
128	
129	  // Transport actions
130	  play: () => {
131	    set({ transportState: "playing" });
132	  },
133	  pause: () => {
134	    set({ transportState: "paused" });
135	  },
136	  stop: () => {
137	    set({ transportState: "stopped", cursorSeconds: 0 });
138	  },
139	  setBpm: (bpm: number) => {
140	    const clamped = Math.min(999, Math.max(20, bpm));
141	    if (!Number.isFinite(clamped)) return;
142	    set({ bpm: clamped });
143	  },
144	  setCursor: (seconds: number) => {
145	    set({ cursorSeconds: seconds });
146	  },
147	  setLoop: (enabled: boolean, start?: number, end?: number) => {
148	    set((state) => ({
149	      loopEnabled: enabled,
150	      loopStart: start ?? state.loopStart,
151	      loopEnd: end ?? state.loopEnd,
152	    }));
153	  },
154	
155	  // Engine actions
156	  setEngineStatus: (status: AudioEngineStatus) => {
157	    set({ engineStatus: status });
158	  },
159	
160	  // Mixer actions
161	  setMasterVolume: (volume: number) => {
162	    const clamped = Math.min(2, Math.max(0, volume));
163	    set({ masterVolume: clamped });
164	  },
165	
166	  // Track actions
167	  addTrack: (track: TrackModel, index?: number) => {
168	    set((state) => {
169	      const next = [...state.tracks];
170	      if (index !== undefined) {
171	        next.splice(index, 0, track);
172	      } else {
173	        next.push(track);
174	      }
175	      return { tracks: next };
176	    });
177	  },
178	
179	  removeTrack: (id: string) => {
180	    set((state) => {
181	      const track = state.tracks.find((t) => t.id === id);
182	      if (!track) return state;
183	      const removeSet = new Set(track.clipIds);
184	      const nextClips = Object.fromEntries(
185	        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
186	      );
187	      return {
188	        tracks: state.tracks.filter((t) => t.id !== id),
189	        clips: nextClips,
190	      };
191	    });
192	  },
193	
194	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
195	    set((state) => ({
196	      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
197	    }));
198	  },
199	
200	  reorderTrack: (id: string, toIndex: number) => {
201	    set((state) => {
202	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
203	      if (fromIndex === -1) return state;
204	      const next = [...state.tracks];
205	      const moved = next.splice(fromIndex, 1)[0];
206	      if (moved === undefined) return state;
207	      next.splice(toIndex, 0, moved);
208	      return { tracks: next };
209	    });
210	  },
211	
212	  // Clip actions
213	  addClip: (clip: ClipModel) => {
214	    set((state) => {
215	      const nextClips = { ...state.clips, [clip.id]: clip };
216	      const tracks = state.tracks.map((t) =>
217	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
218	      );
219	      return { clips: nextClips, tracks };
220	    });
221	  },
222	
223	  removeClip: (id: string) => {
224	    set((state) => {
225	      const clip = state.clips[id];
226	      if (!clip) return state;
227	      const nextClips = Object.fromEntries(
228	        Object.entries(state.clips).filter(([k]) => k !== id),
229	      );
230	      const tracks = state.tracks.map((t) =>
231	        t.id === clip.trackId
232	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
233	          : t,
234	      );
235	      return { clips: nextClips, tracks };
236	    });
237	  },
238	
239	  moveClip: (id: string, startTime: number, toTrackId?: string) => {
240	    set((state) => {
241	      const clip = state.clips[id];
242	      if (!clip) return state;
243	      const updatedClip = {
244	        ...clip,
245	        startTime,
246	        trackId: toTrackId ?? clip.trackId,
247	      };
248	      const nextClips = { ...state.clips, [id]: updatedClip };
249	
250	      let tracks = state.tracks;
251	      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
252	        tracks = tracks.map((t) => {
253	          if (t.id === clip.trackId) {
254	            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
255	          }
256	          if (t.id === toTrackId) {
257	            return { ...t, clipIds: [...t.clipIds, id] };
258	          }
259	          return t;
260	        });
261	      }
262	      return { clips: nextClips, tracks };
263	    });
264	  },
265	
266	  splitClip: (
267	    id: string,
268	    atTime: number,
269	    providedId?: string,
270	  ): string | undefined => {
271	    const state = get();
272	    const clip = state.clips[id];
273	    if (!clip) return undefined;
274	    if (!isAudioClip(clip)) return undefined;
275	
276	    const clipEnd = clip.startTime + clip.duration;
277	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
278	
279	    const leftDuration = atTime - clip.startTime;
280	    const rightDuration = clip.duration - leftDuration;
281	    const rightSourceOffset = clip.sourceOffset + leftDuration;
282	
283	    const newId = providedId ?? nextClipId();
284	
285	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
286	    const rightClip: ClipModel = {
287	      ...clip,
288	      id: newId,
289	      startTime: atTime,
290	      sourceOffset: rightSourceOffset,
291	      duration: rightDuration,
292	    };
293	
294	    set((s) => {
295	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
296	      const tracks = s.tracks.map((t) =>
297	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
298	      );
299	      return { clips: nextClips, tracks };
300	    });
301	
302	    return newId;
303	  },
304	
305	  trimClip: (id: string, newStart?: number, newEnd?: number) => {
306	    set((state) => {
307	      const clip = state.clips[id];
308	      if (!clip) return state;
309	      if (!isAudioClip(clip)) return state;
310	
311	      let { startTime, sourceOffset, duration } = clip;
312	      const clipEnd = startTime + duration;
313	
314	      if (newStart !== undefined) {
315	        const delta = newStart - startTime;
316	        startTime = newStart;
317	        sourceOffset = sourceOffset + delta;
318	        duration = clipEnd - newStart;
319	      }
320	
321	      if (newEnd !== undefined) {
322	        duration = newEnd - startTime;
323	      }
324	
325	      // Guard against invalid state
326	      if (duration <= 0 || sourceOffset < 0) return state;
327	
328	      return {
329	        clips: {
330	          ...state.clips,
331	          [id]: { ...clip, startTime, sourceOffset, duration },
332	        },
333	      };
334	    });
335	  },
336	
337	  duplicateClip: (id: string, providedId?: string): string | undefined => {
338	    const state = get();
339	    const clip = state.clips[id];
340	    if (!clip) return undefined;
341	
342	    const newId = providedId ?? nextClipId();
343	    const duplicate: ClipModel = {
344	      ...clip,
345	      id: newId,
346	      startTime: clip.startTime + clip.duration,
347	    };
348	
349	    set((s) => {
350	      const nextClips = { ...s.clips, [newId]: duplicate };
351	      const tracks = s.tracks.map((t) =>
352	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
353	      );
354	      return { clips: nextClips, tracks };
355	    });
356	
357	    return newId;
358	  },
359	
360	  // MIDI clip actions
361	  addMidiClip: (clip: MidiClipModel) => {
362	    set((state) => {
363	      const nextClips = { ...state.clips, [clip.id]: clip };
364	      const tracks = state.tracks.map((t) =>
365	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
366	      );
367	      return { clips: nextClips, tracks };
368	    });
369	  },
370	
371	  removeMidiClip: (id: string) => {
372	    set((state) => {
373	      const clip = state.clips[id];
374	      if (!clip) return state;
375	      const nextClips = Object.fromEntries(
376	        Object.entries(state.clips).filter(([k]) => k !== id),
377	      );
378	      const tracks = state.tracks.map((t) =>
379	        t.id === clip.trackId
380	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
381	          : t,
382	      );
383	      return { clips: nextClips, tracks };
384	    });
385	  },
386	
387	  addNoteEvent: (clipId: string, note: MIDINoteEvent) => {
388	    set((state) => {
389	      const clip = state.clips[clipId];
390	      if (!clip || !isMidiClip(clip)) return state;
391	      const clamped: MIDINoteEvent = {
392	        ...note,
393	        pitch: Math.max(0, Math.min(127, Math.round(note.pitch))),
394	        velocity: Math.max(0, Math.min(127, Math.round(note.velocity))),
395	        startTime: Math.max(0, note.startTime),
396	        duration: Math.max(0.01, note.duration),
397	      };
398	      const updated: MidiClipModel = {
399	        ...clip,
400	        noteEvents: [...clip.noteEvents, clamped],
401	      };
402	      return { clips: { ...state.clips, [clipId]: updated } };
403	    });
404	  },
405	
406	  removeNoteEvent: (clipId: string, noteId: string) => {
407	    set((state) => {
408	      const clip = state.clips[clipId];
409	      if (!clip || !isMidiClip(clip)) return state;
410	      const updated: MidiClipModel = {
411	        ...clip,
412	        noteEvents: clip.noteEvents.filter((n) => n.id !== noteId),
413	      };
414	      return { clips: { ...state.clips, [clipId]: updated } };
415	    });
416	  },
417	
418	  moveNoteEvent: (
419	    clipId: string,
420	    noteId: string,
421	    newStartTime: number,
422	    newPitch: number,
423	  ) => {
424	    set((state) => {
425	      const clip = state.clips[clipId];
426	      if (!clip || !isMidiClip(clip)) return state;
427	      const clampedPitch = Math.max(0, Math.min(127, Math.round(newPitch)));
428	      const clampedStartTime = Math.max(0, newStartTime);
429	      const updated: MidiClipModel = {
430	        ...clip,
431	        noteEvents: clip.noteEvents.map((n) =>
432	          n.id === noteId
433	            ? { ...n, startTime: clampedStartTime, pitch: clampedPitch }
434	            : n,
435	        ),
436	      };
437	      return { clips: { ...state.clips, [clipId]: updated } };
438	    });
439	  },
440	
441	  resizeNoteEvent: (clipId: string, noteId: string, newDuration: number) => {
442	    set((state) => {
443	      const clip = state.clips[clipId];
444	      if (!clip || !isMidiClip(clip)) return state;
445	      const clampedDuration = Math.max(0.01, newDuration);
446	      const updated: MidiClipModel = {
447	        ...clip,
448	        noteEvents: clip.noteEvents.map((n) =>
449	          n.id === noteId ? { ...n, duration: clampedDuration } : n,
450	        ),
451	      };
452	      return { clips: { ...state.clips, [clipId]: updated } };
453	    });
454	  },
455	
456	  updateNoteVelocity: (clipId: string, noteId: string, velocity: number) => {
457	    set((state) => {
458	      const clip = state.clips[clipId];
459	      if (!clip || !isMidiClip(clip)) return state;
460	      const clampedVelocity = Math.max(0, Math.min(127, Math.round(velocity)));
461	      const updated: MidiClipModel = {
462	        ...clip,
463	        noteEvents: clip.noteEvents.map((n) =>
464	          n.id === noteId ? { ...n, velocity: clampedVelocity } : n,
465	        ),
466	      };
467	      return { clips: { ...state.clips, [clipId]: updated } };
468	    });
469	  },
470	
471	  // Selection
472	  setSelectedTrackIds: (ids: readonly string[]) => {
473	    set({ selectedTrackIds: ids });
474	  },
475	  setSelectedClipIds: (ids: readonly string[]) => {
476	    set({ selectedClipIds: ids });
477	  },
478	  setSelectedNoteIds: (ids: readonly string[]) => {
479	    set({ selectedNoteIds: ids });
480	  },
481	
482	  // Query
483	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
484	    const state = get();
485	    const hasSolo = state.tracks.some((t) => t.solo);
486	    const activeTracks = new Set(
487	      state.tracks
488	        .filter((t) => {
489	          if (t.muted) return false;
490	          if (hasSolo && !t.solo && !t.soloIsolate) return false;
491	          return true;
492	        })
493	        .map((t) => t.id),
494	    );
495	
496	    return Object.values(state.clips).filter((clip) => {
497	      if (!activeTracks.has(clip.trackId)) return false;
498	      const clipEnd = clip.startTime + clip.duration;
499	      return time >= clip.startTime && time < clipEnd;
500	    });
501	  },
502	}));
503

1	/**
2	 * Core types for the track system.
3	 * Tracks contain clips; clips are non-destructive references to audio sources
4	 * or containers for MIDI note events.
5	 */
6	
7	export type TrackType = "audio" | "instrument";
8	
9	export type MIDINoteEvent = {
10	  readonly id: string;
11	  readonly pitch: number; // 0-127
12	  readonly velocity: number; // 0-127
13	  readonly startTime: number; // seconds, relative to clip start
14	  readonly duration: number; // seconds
15	};
16	
17	export type AudioClipModel = {
18	  readonly type: "audio";
19	  readonly id: string;
20	  readonly trackId: string;
21	  readonly sourceId: string;
22	  readonly startTime: number; // seconds on timeline
23	  readonly sourceOffset: number; // seconds into source
24	  readonly duration: number; // seconds
25	  readonly gain: number; // 0..2
26	  readonly fadeIn: number; // seconds
27	  readonly fadeOut: number; // seconds
28	  readonly name: string;
29	};
30	
31	export type MidiClipModel = {
32	  readonly type: "midi";
33	  readonly id: string;
34	  readonly trackId: string;
35	  readonly startTime: number; // seconds on timeline
36	  readonly duration: number; // seconds
37	  readonly noteEvents: readonly MIDINoteEvent[];
38	  readonly name: string;
39	};
40	
41	export type ClipModel = AudioClipModel | MidiClipModel;
42	
43	export function isAudioClip(clip: ClipModel): clip is AudioClipModel {
44	  return clip.type === "audio";
45	}
46	
47	export function isMidiClip(clip: ClipModel): clip is MidiClipModel {
48	  return clip.type === "midi";
49	}
50	
51	export type TrackModel = {
52	  readonly id: string;
53	  readonly name: string;
54	  readonly type: TrackType;
55	  readonly color: string;
56	  readonly muted: boolean;
57	  readonly solo: boolean;
58	  readonly armed: boolean;
59	  readonly soloIsolate: boolean;
60	  readonly volume: number; // 0..2
61	  readonly pan: number; // -1..1
62	  readonly clipIds: readonly string[];
63	};
64

1	/**
2	 * Types for the mixer audio engine.
3	 * Channel strips, master bus, insert chain infrastructure.
4	 */
5	
6	export type InsertSlot = {
7	  readonly id: string;
8	  readonly node: AudioNode | null; // null = empty slot
9	  readonly bypassed: boolean;
10	};
11	
12	export type ChannelStrip = {
13	  readonly trackId: string;
14	  /** Pre-insert input gain */
15	  readonly inputGain: GainNode;
16	  /** Ordered insert chain (empty initially) */
17	  readonly inserts: readonly InsertSlot[];
18	  /** Pre-fader tap point for pre-fader sends (after inserts, before fader) */
19	  readonly preFaderTap: GainNode;
20	  /** Post-insert fader (logarithmic taper via GainNode) */
21	  readonly faderGain: GainNode;
22	  /** Stereo panner */
23	  readonly panner: StereoPannerNode;
24	  /** Mute control (gain 0 or 1) */
25	  readonly muteGain: GainNode;
26	  /** AnalyserNode for metering */
27	  readonly analyser: AnalyserNode;
28	  /** Whether this channel is muted */
29	  muted: boolean;
30	  /** Whether this channel is soloed */
31	  solo: boolean;
32	  /** Whether this channel has solo-isolate enabled */
33	  soloIsolate: boolean;
34	};
35	
36	export type MasterBus = {
37	  /** Sum input from all channel strips */
38	  readonly inputGain: GainNode;
39	  /** Master fader */
40	  readonly faderGain: GainNode;
41	  /**
42	   * INV-2: Non-bypassable brickwall limiter.
43	   * DynamicsCompressorNode: threshold=-1dBFS, ratio=20:1, knee=0,
44	   * attack=0.001s, release=0.01s
45	   */
46	  readonly limiter: DynamicsCompressorNode;
47	  /** Master analyser for metering */
48	  readonly analyser: AnalyserNode;
49	};
50	
51	export type MixerEngine = {
52	  /** Get or create a channel strip for a track */
53	  getOrCreateStrip(trackId: string): ChannelStrip;
54	  /** Remove a channel strip */
55	  removeStrip(trackId: string): void;
56	  /** Get an existing strip */
57	  getStrip(trackId: string): ChannelStrip | undefined;
58	  /** Get all channel strips */
59	  getAllStrips(): readonly ChannelStrip[];
60	  /** Get master bus */
61	  getMaster(): MasterBus;
62	
63	  /** Set fader level (0..2, logarithmic taper applied internally) */
64	  setFaderLevel(trackId: string, level: number): void;
65	  /** Set pan (-1..1) */
66	  setPan(trackId: string, pan: number): void;
67	  /** Set mute state */
68	  setMute(trackId: string, muted: boolean): void;
69	  /** Set solo state */
70	  setSolo(trackId: string, solo: boolean): void;
71	  /** Set solo-isolate state */
72	  setSoloIsolate(trackId: string, enabled: boolean): void;
73	  /** Set master fader level */
74	  setMasterLevel(level: number): void;
75	
76	  /** Recompute mute states based on solo-in-place logic */
77	  updateSoloState(): void;
78	
79	  /** Get the output node to connect sources to for a track */
80	  getTrackInput(trackId: string): AudioNode;
81	
82	  /** Add an effect insert to a track's insert chain */
83	  addInsert(
84	    trackId: string,
85	    id: string,
86	    input: AudioNode,
87	    output: AudioNode,
88	  ): void;
89	  /** Replace an effect insert in-place (preserves chain order) */
90	  replaceInsert(
91	    trackId: string,
92	    id: string,
93	    input: AudioNode,
94	    output: AudioNode,
95	  ): void;
96	  /** Remove an effect insert from a track's insert chain */
97	  removeInsert(trackId: string, insertId: string): void;
98	
99	  /** Emergency mute master */
100	  emergencyMute(): void;
101	  /** Release emergency mute */
102	  releaseEmergencyMute(): void;
103	
104	  /** Dispose all nodes */
105	  dispose(): void;
106	};
107

1	/**
2	 * AudioContext lifecycle management.
3	 * Handles creation, suspension, resumption on user gesture,
4	 * and AudioWorklet module loading.
5	 */
