### Parameter Application Pattern (src/audio/effects/create-effect.ts)
```typescript
// Ramp time: 5ms to avoid clicks
const RAMP_TIME = 0.005;

function rampTo(param: AudioParam, value: number): void {
  if (typeof param.linearRampToValueAtTime === "function") {
    param.setValueAtTime(param.value, ctx.currentTime);
    param.linearRampToValueAtTime(value, ctx.currentTime + RAMP_TIME);
  } else {
    param.value = value;  // Fallback
  }
}
```

