  meta: { name: string; createdAt: number; updatedAt: number };
  transport: { bpm: number; loopEnabled: boolean; loopStart: number; loopEnd: number };
  tracks: TrackSchema[];
  clips: ClipSchema[];
  mixer: { masterVolume: number };
  effects?: { trackId: string; slots: EffectSlotState[] }[];
  modulation?: Record<string, ModulationRoute[]>;
  arpeggiator?: Record<string, ArpParams>;
}
```

**Key Points:**
- Zod for runtime validation
- **No automation section** in schema
- Would need to add: `automation?: Record<string, AutomationLane[]>`

**Persistence Flow:**
1. `useSessionPersistence` hook
2. `saveQueue` for batching writes
3. `auto-save` with 5-second debounce
4. IndexedDB storage

---

## 9. Synth System (src/state/synth/)

### Synth Parameter Map
```typescript
type SynthParameterMap = {
  // Oscillators
  osc1Type: WaveformType;       // "sine", "saw", "square", "triangle"
  osc1Octave: number;           // -2..+2
  osc1Detune: number;           // cents, -100..+100
  osc1Level: number;            // 0..1
  osc2Type/Octave/Detune/Level;

  // Filter
  filterType: FilterType;        // "lowpass", "highpass", "bandpass"
  filterCutoff: number;          // Hz, 20..20000
  filterResonance: number;       // Q, 0.5..20

  // Envelopes (ADSR)
  ampAttack/Decay/Sustain/Release;
  filterAttack/Decay/Sustain/Release;
  filterEnvDepth: number;        // semitones, -60..+60

  // LFOs
  lfo1Rate: number;              // Hz, 0.1..20
  lfo1Depth: number;             // 0..1
  lfo1Shape: LFOShape;           // "sine", "square", "triangle", "sample-and-hold"
  lfo2Rate/Depth/Shape;

  // Glide
  glideTime: number;             // 0..1 seconds

  // Master
  masterGain: number;            // 0..1
}
```

**Synth Store (Zustand):**
```typescript
type SynthStore = {
  synths: Record<string, SynthTrackState>;
  setParam<K extends keyof SynthParameterMap>(trackId, key, value);
  // ... other methods
}
```

**Observations:**
- **All params are static values** (no time-based changes)
- Stored per-track instrument
- **No per-note automation** in synth layer
- Modulation matrix can modulate destinations (see below)

---

## 10. Effects System (src/audio/effects/ + src/state/effects/)

### Effect Architecture
```typescript
// State layer
type EffectSlotState = {
  id: string;
  typeId: string;              // e.g., "compressor", "delay"
  bypassed: boolean;
  params: Record<string, number>;
};

// Audio layer
type EffectInstance = {
  id: string;
  typeId: string;
  input: AudioNode;
  output: AudioNode;
  dryGain: GainNode;
  wetGain: GainNode;
  getParam(key: string): number;
  setParam(key: string, value: number): void;
  setBypassed(bypassed: boolean): void;
  setMix(wet: number): void;    // 0..1
  dispose(): void;
}
```

**Effect Parameter Schema:**
```typescript
type EffectParameterSchema = {
  name: string;
  key: string;
  min: number;
  max: number;
  default: number;
  step: number;
  unit: string;
}
```

### Parameter Application Pattern (src/audio/effects/create-effect.ts)
```typescript
// Ramp time: 5ms to avoid clicks
const RAMP_TIME = 0.005;

function rampTo(param: AudioParam, value: number): void {
  if (typeof param.linearRampToValueAtTime === "function") {
    param.setValueAtTime(param.value, ctx.currentTime);
    param.linearRampToValueAtTime(value, ctx.currentTime + RAMP_TIME);
  } else {
    param.value = value;  // Fallback
  }
}
```

**Key Observations:**
- **Uses AudioParam ramping** for smooth transitions (5ms)
- `setParam()` is called from state updates
- **No look-ahead automation** in effects
- Each effect has its own param storage
- Wet/dry split with gain-based mixing

### Built-in Effects
- Compressor (DynamicsCompressorNode)
- EQ (Biquad filters)
- Delay
- Reverb (Freeverb algorithm)
- Chorus
- Distortion

---

## 11. Undo System (src/state/undo/)

### Command Pattern
```typescript
type UndoCommand = {
  readonly type: string;
  execute(): void;
  undo(): void;
  serialize(): Record<string, unknown>;
}

type UndoManager = {
  push(command: UndoCommand): void;
  undo(): boolean;
  redo(): boolean;
  clear(): void;
  readonly canUndo: boolean;
  readonly canRedo: boolean;
  readonly undoStack: readonly UndoCommand[];
  readonly redoStack: readonly UndoCommand[];
  readonly size: number;
}
```

**Implementation:**
- Maintains undo/redo stacks
- Max 200 commands by default
- Commands are executed immediately, then pushed
- Redo stack clears when new command pushed

**Existing Commands:**
- `AddTrackCommand`, `RemoveTrackCommand`
- `AddClipCommand`, `RemoveClipCommand`
- Move, split, trim, duplicate clips
- Note operations (add, remove, move, resize)

**For Automation:**
- Need: `AddAutomationPointCommand`, `RemoveAutomationPointCommand`
- Need: `UpdateAutomationPointCommand`
- Need: `AutomationCurveTypeChangeCommand`

---

## 12. Modulation System (src/audio/synth/modulation-types.ts + modulation-engine.ts)

### Modulation Matrix (Real-Time Parameter Control)
```typescript
// Available sources
const MOD_SOURCES = [
  "lfo1", "lfo2",                    // Synth LFOs
  "ampEnv", "filterEnv",             // ADSR envelopes
  "velocity", "aftertouch",          // Performance
  "modWheel", "pitchBend"            // Controller input
] as const;

// Available destinations
const MOD_DESTINATIONS = [
  "osc1Pitch", "osc2Pitch",          // Pitch modulation
  "oscMix",                          // Mix between oscillators
  "filterCutoff", "filterResonance", // Filter mod
  "ampLevel",                        // Amplitude mod
  "lfo1Rate", "lfo2Rate"             // LFO rate mod
] as const;

type ModRoute = {
  id: string;
  source: ModSource;
  destination: ModDestination;
  amount: number; // -1..+1
  bipolar: boolean;
}
```

### Modulation Engine (AudioWorklet)
```typescript
// Pre-allocated per quantum
type ModAccumulators = {
  osc1Pitch: number;
  osc2Pitch: number;
  oscMix: number;
  filterCutoff: number;
  filterResonance: number;
  ampLevel: number;
  lfo1Rate: number;
  lfo2Rate: number;
}

// Per-sample processing
function applyModRoute(
  acc: ModAccumulators,
  sourceValues: Float64Array,    // Per-source current values
  sourceIdx: number,
  destIdx: number,
  amount: number,
  bipolar: boolean
): void
```

**Key Architecture:**
- **Zero-allocation design** for audio thread
- Routes applied in **sample-accurate loop**
- Accumulators reset each quantum
- Source values read from SAB or internal state
- Uses index-based routing (numeric, not string keys)

**Observations:**
- This is the **closest existing thing to automation**
- Differs from automation: **always active, not clip-specific**
- Could be **extended with time-based source values** for automation

---

## 13. Clip Scheduler (src/audio/mixer/clip-scheduler.ts)

### Playback Scheduling Pattern
```typescript
type ClipScheduler = {
  scheduleClips(
    clips: readonly AudioClipModel[],
    windowStart: number;          // AudioContext time
    windowEnd: number;
    timeOffset: number;           // arrangement → audio time
    getBuffer: (sourceId: string) => AudioBuffer | undefined;
    destination: AudioNode;
  ): void;
  stopAll(): void;
  cleanup(): void;
}
```

**Implementation Details:**
1. **Converts arrangement time to AudioContext time** using offset
2. **Checks if clip overlaps look-ahead window**
3. **Creates AudioBufferSourceNode + GainNode per clip**
4. **Applies fade-in/fade-out** with `linearRampToValueAtTime`
5. **Handles mid-clip seeking**
6. **Pre-allocates arrays** (no allocs during scheduling)

**Fade Application Pattern:**
```typescript
// Fade-in example
gainNode.gain.setValueAtTime(startGain, fadeInStart);
gainNode.gain.linearRampToValueAtTime(clip.gain, fadeInEnd);

// Fade-out
gainNode.gain.setValueAtTime(clip.gain, fadeOutStart);
gainNode.gain.linearRampToValueAtTime(0, fadeOutEnd);
```

**For Automation:**
- This is **exactly where envelope/curve scheduling happens**
- Could extend to apply **automation envelopes** alongside fades
- Natural place to **sample automation curves** at clip boundaries

---

## Summary: Automation Readiness Analysis

### What Exists for Automation
1. ✅ **Precise timing system** (TransportClock + TempoMap)
2. ✅ **Look-ahead scheduler** with beat sync
3. ✅ **AudioParam ramping** infrastructure (effects use it)
4. ✅ **Modulation matrix** (real-time parameter mod, but always-on)
5. ✅ **Session persistence** with extensible schema
6. ✅ **Undo/redo system** for command-based operations
7. ✅ **Mixer architecture** (fader, pan, mute per track)
8. ✅ **Insert chain** (effects automation possible)

### What's Missing
1. ❌ **Automation lane data structure** (ClipModel, TrackModel)
2. ❌ **Automation point/keyframe storage** (position, value, curve type)
3. ❌ **Curve interpolation/evaluation** functions
4. ❌ **Automation lane rendering** in arrangement UI
5. ❌ **Automation lane interaction** (UI for adding/editing points)
6. ❌ **Parameter scheduling** at clip-level (vs global modulation)
7. ❌ **Curve type support** (linear, exponential, exponential-ramp, etc.)
8. ❌ **State layer** for automation (Zustand store)

### Key Architectural Points
- **No existing automation** but perfect foundation
- **Transport clock guarantees sample-accurate timing**
- **Look-ahead scheduler can pre-compute automation curves**
- **SharedArrayBuffer ensures tight audio thread sync**
- **Undo system ready for automation commands**
- **Session persistence just needs schema extension**

