1	/**
2	 * Core types for the automation system.
3	 * Automation lanes contain breakpoint curves that control parameters over time.
4	 */
5	
6	/** Interpolation mode between automation points */
7	export type InterpolationMode = "linear" | "curved";
8	
9	/** Automation playback/recording mode */
10	export type AutomationMode = "read" | "write" | "touch";
11	
12	/** A single automation breakpoint */
13	export type AutomationPoint = {
14	  readonly id: string;
15	  /** Time position in seconds on the arrangement timeline */
16	  readonly time: number;
17	  /** Normalized value 0..1 (mapped to parameter range externally) */
18	  readonly value: number;
19	  /** Interpolation mode to the NEXT point */
20	  readonly interpolation: InterpolationMode;
21	  /** Bezier curve tension for "curved" interpolation (-1..1, 0 = linear) */
22	  readonly curve: number;
23	};
24	
25	/** Target parameter that an automation lane controls */
26	export type ParameterTarget =
27	  | { readonly type: "mixer"; readonly param: "volume" | "pan" }
28	  | {
29	      readonly type: "effect";
30	      readonly effectId: string;
31	      readonly paramKey: string;
32	    }
33	  | {
34	      readonly type: "synth";
35	      readonly paramKey: string;
36	    };
37	
38	/** A single automation lane associated with a track */
39	export type AutomationLane = {
40	  readonly id: string;
41	  readonly trackId: string;
42	  readonly target: ParameterTarget;
43	  readonly points: readonly AutomationPoint[];
44	  readonly mode: AutomationMode;
45	  /** Whether automation is actively overriding manual control */
46	  readonly armed: boolean;
47	};
48	
49	/** Range definition for mapping normalized 0..1 to actual parameter values */
50	export type ParameterRange = {
51	  readonly min: number;
52	  readonly max: number;
53	};
54	
55	/** Default automation mode */
56	export const DEFAULT_AUTOMATION_MODE: AutomationMode = "read";
57

1	/**
2	 * Pure functions for automation curve evaluation and point manipulation.
3	 * All operations are immutable - they return new arrays.
4	 */
5	
6	import type { AutomationPoint, ParameterRange } from "./automation-types";
7	
8	/**
9	 * Evaluate an automation curve at a given time position.
10	 * Returns normalized value (0..1).
11	 *
12	 * - Before first point: holds first point value
13	 * - After last point: holds last point value
14	 * - Between points: interpolates based on left point's interpolation mode
15	 */
16	export function evaluateCurve(
17	  points: readonly AutomationPoint[],
18	  time: number,
19	): number {
20	  if (points.length === 0) return 0;
21	  if (points.length === 1) return points[0]!.value;
22	
23	  // Before first point
24	  if (time <= points[0]!.time) return points[0]!.value;
25	
26	  // After last point
27	  const last = points[points.length - 1]!;
28	  if (time >= last.time) return last.value;
29	
30	  // Find segment: binary search for left point
31	  let lo = 0;
32	  let hi = points.length - 1;
33	  while (lo < hi - 1) {
34	    const mid = (lo + hi) >>> 1;
35	    if (points[mid]!.time <= time) {
36	      lo = mid;
37	    } else {
38	      hi = mid;
39	    }
40	  }
41	
42	  const left = points[lo]!;
43	  const right = points[hi]!;
44	
45	  // Compute parameter t within segment
46	  const dt = right.time - left.time;
47	  if (dt === 0) return left.value;
48	  const t = (time - left.time) / dt;
49	
50	  if (left.interpolation === "linear" || left.curve === 0) {
51	    return left.value + (right.value - left.value) * t;
52	  }
53	
54	  // Curved interpolation: exponential-style curve using power function
55	  // curve > 0 = convex (fast start), curve < 0 = concave (slow start)
56	  const shapedT = shapeCurve(t, left.curve);
57	  return left.value + (right.value - left.value) * shapedT;
58	}
59	
60	/**
61	 * Shape a linear t (0..1) using a curve parameter (-1..1).
62	 * Positive curve = convex (fast start, slow end).
63	 * Negative curve = concave (slow start, fast end).
64	 * Zero = linear.
65	 */
66	function shapeCurve(t: number, curve: number): number {
67	  if (curve === 0) return t;
68	  // Map curve (-1..1) to exponent: curve=-1 -> exp=3, curve=0 -> exp=1, curve=1 -> exp=1/3
69	  const exponent = Math.pow(3, -curve);
70	  return Math.pow(t, exponent);
71	}
72	
73	/** Map normalized value (0..1) to actual parameter range */
74	export function denormalize(normalized: number, range: ParameterRange): number {
75	  return range.min + normalized * (range.max - range.min);
76	}
77	
78	/** Map actual parameter value to normalized (0..1), clamped */
79	export function normalize(value: number, range: ParameterRange): number {
80	  const span = range.max - range.min;
81	  if (span === 0) return 0;
82	  return Math.max(0, Math.min(1, (value - range.min) / span));
83	}
84	
85	/** Insert a point maintaining time-sorted order (immutable) */
86	export function insertPoint(
87	  points: readonly AutomationPoint[],
88	  point: AutomationPoint,
89	): readonly AutomationPoint[] {
90	  const idx = points.findIndex((p) => p.time > point.time);
91	  if (idx === -1) return [...points, point];
92	  return [...points.slice(0, idx), point, ...points.slice(idx)];
93	}
94	
95	/** Remove a point by id (immutable) */
96	export function removePoint(
97	  points: readonly AutomationPoint[],
98	  pointId: string,
99	): readonly AutomationPoint[] {
100	  const filtered = points.filter((p) => p.id !== pointId);
101	  return filtered.length === points.length ? points : filtered;
102	}
103	
104	/** Move a point to new time/value, re-sorting by time (immutable) */
105	export function movePoint(
106	  points: readonly AutomationPoint[],
107	  pointId: string,
108	  newTime: number,
109	  newValue: number,
110	): readonly AutomationPoint[] {
111	  const idx = points.findIndex((p) => p.id === pointId);
112	  if (idx === -1) return points;
113	  const existing = points[idx]!;
114	  const updated: AutomationPoint = {
115	    ...existing,
116	    time: newTime,
117	    value: newValue,
118	  };
119	  const without = [...points.slice(0, idx), ...points.slice(idx + 1)];
120	  return insertPoint(without, updated);
121	}
