20	function nextLaneId(): string {
21	  return `lane-${++laneCounter}`;
22	}
23	
24	export type AutomationStore = {
25	  /** Per-track automation lanes keyed by track ID */
26	  lanes: Record<string, readonly AutomationLane[]>;
27	
28	  addLane: (trackId: string, target: ParameterTarget) => void;
29	  removeLane: (trackId: string, laneId: string) => void;
30	  removeTrackLanes: (trackId: string) => void;
31	  addPoint: (
32	    trackId: string,
33	    laneId: string,
34	    point: AutomationPoint,
35	  ) => void;
36	  removePoint: (
37	    trackId: string,
38	    laneId: string,
39	    pointId: string,
40	  ) => void;
41	  movePoint: (
42	    trackId: string,
43	    laneId: string,
44	    pointId: string,
45	    newTime: number,
46	    newValue: number,
47	  ) => void;
48	  setMode: (trackId: string, laneId: string, mode: AutomationMode) => void;
49	  setArmed: (trackId: string, laneId: string, armed: boolean) => void;
50	  getLanes: (trackId: string) => readonly AutomationLane[];
51	  getLane: (trackId: string, laneId: string) => AutomationLane | undefined;
52	};
53	
54	function updateLane(
55	  lanes: readonly AutomationLane[],
56	  laneId: string,
57	  updater: (lane: AutomationLane) => AutomationLane,
58	): readonly AutomationLane[] {
59	  return lanes.map((l) => (l.id === laneId ? updater(l) : l));
60	}
61	
62	export const useAutomationStore = create<AutomationStore>()((set, get) => ({
63	  lanes: {},
64	
65	  addLane(trackId, target) {
66	    set((s) => {
67	      const existing = s.lanes[trackId] ?? [];
68	      const lane: AutomationLane = {
69	        id: nextLaneId(),
70	        trackId,
71	        target,
72	        points: [],
73	        mode: "read",
74	        armed: true,
75	      };
76	      return {
77	        lanes: { ...s.lanes, [trackId]: [...existing, lane] },
78	      };
79	    });
80	  },
81	
82	  removeLane(trackId, laneId) {
83	    set((s) => {
84	      const existing = s.lanes[trackId];
85	      if (!existing) return s;
86	      const next = existing.filter((l) => l.id !== laneId);
87	      if (next.length === 0) {
88	        return {
89	          lanes: Object.fromEntries(
90	            Object.entries(s.lanes).filter(([k]) => k !== trackId),
91	          ),
92	        };
93	      }
94	      return { lanes: { ...s.lanes, [trackId]: next } };
95	    });
96	  },
97	
