15	export type ArpeggiatorStore = {
16	  /** Per-track arpeggiator state keyed by track ID */
17	  arps: Record<string, ArpTrackState>;
18	
19	  /** Initialize arpeggiator state for a track */
20	  initArp: (trackId: string) => void;
21	  /** Remove arpeggiator state for a track */
22	  removeArp: (trackId: string) => void;
23	  /** Set a single arpeggiator parameter for a track */
24	  setParam: <K extends keyof ArpParams>(
25	    trackId: string,
26	    key: K,
27	    value: ArpParams[K],
28	  ) => void;
29	  /** Set all arpeggiator parameters for a track */
30	  setParams: (trackId: string, params: ArpParams) => void;
31	  /** Get arp params for a track (returns defaults if not initialized) */
32	  getParams: (trackId: string) => ArpParams;
33	};
34	
35	export const useArpeggiatorStore = create<ArpeggiatorStore>()((set, get) => ({
36	  arps: {},
37	
38	  initArp(trackId) {
39	    set((s) => {
40	      if (s.arps[trackId]) return s;
41	      return {
42	        arps: {
43	          ...s.arps,
44	          [trackId]: {
45	            trackId,
46	            params: { ...DEFAULT_ARP_PARAMS },
47	          },
48	        },
49	      };
50	    });
51	  },
52	
53	  removeArp(trackId) {
54	    set((s) => {
55	      if (!s.arps[trackId]) return s;
56	      return {
57	        arps: Object.fromEntries(
58	          Object.entries(s.arps).filter(([k]) => k !== trackId),
59	        ),
60	      };
61	    });
62	  },
63	
64	  setParam(trackId, key, value) {
65	    set((s) => {
66	      const arp = s.arps[trackId];
67	      if (!arp) return s;
68	      return {
69	        arps: {
70	          ...s.arps,
71	          [trackId]: {
72	            ...arp,
73	            params: { ...arp.params, [key]: value },
74	          },
75	        },
76	      };
77	    });
78	  },
79	
80	  setParams(trackId, params) {
81	    set((s) => {
82	      const arp = s.arps[trackId];
83	      if (!arp) return s;
84	      return {
85	        arps: {
86	          ...s.arps,
87	          [trackId]: { ...arp, params },
88	        },
89	      };
90	    });
91	  },
92	
93	  getParams(trackId) {
94	    const arp = get().arps[trackId];
95	    return arp?.params ?? { ...DEFAULT_ARP_PARAMS };
96	  },
97	}));
