26	function serializeModulation():
27	  | Record<
28	      string,
29	      {
30	        id: string;
31	        source: string;
32	        destination: string;
33	        amount: number;
34	        bipolar: boolean;
35	      }[]
36	    >
37	  | undefined {
38	  const { matrices } = useModulationStore.getState();
39	  const entries = Object.entries(matrices);
40	  if (entries.length === 0) return undefined;
41	  const result: Record<
42	    string,
43	    {
44	      id: string;
45	      source: string;
46	      destination: string;
47	      amount: number;
48	      bipolar: boolean;
49	    }[]
50	  > = {};
51	  for (const [trackId, matrix] of entries) {
52	    result[trackId] = matrix.routes.map((r) => ({
53	      id: r.id,
54	      source: r.source,
55	      destination: r.destination,
56	      amount: r.amount,
57	      bipolar: r.bipolar,
58	    }));
59	  }
60	  return result;
61	}
