63	function storeToSession(): SessionSchema {
64	  const state = useDawStore.getState();
65	  const effectsState = useEffectsStore.getState();
66	
67	  // Convert effects store to session schema format
68	  const effects = Object.entries(effectsState.trackEffects).map(
69	    ([trackId, slots]) => ({
70	      trackId,
71	      slots: slots.map((s) => ({
72	        id: s.id,
73	        typeId: s.typeId,
74	        bypassed: s.bypassed,
75	        params: { ...s.params },
76	      })),
77	    }),
78	  );
79	
80	  // Convert arpeggiator store to session schema format
81	  const arpEntries = Object.entries(useArpeggiatorStore.getState().arps);
82	  const arpeggiator =
83	    arpEntries.length > 0
84	      ? arpEntries.map(([trackId, state]) => ({
85	          trackId,
86	          params: { ...state.params },
87	        }))
88	      : undefined;
89	
90	  return {
91	    version: SESSION_VERSION,
92	    meta: {
93	      name: sessionMeta.name,
94	      createdAt: sessionMeta.createdAt,
95	      updatedAt: Date.now(),
96	    },
97	    transport: {
98	      bpm: state.bpm,
99	      loopEnabled: state.loopEnabled,
100	      loopStart: state.loopStart,
101	      loopEnd: state.loopEnd,
102	    },
103	    tracks: state.tracks.map((t) => ({ ...t })),
104	    clips: Object.values(state.clips),
105	    mixer: { masterVolume: state.masterVolume },
106	    effects: effects.length > 0 ? effects : undefined,
107	    modulation: serializeModulation(),
108	    arpeggiator,
109	  };
