112	export function hydrateStore(session: SessionSchema): void {
113	  sessionMeta = {
114	    name: session.meta.name,
115	    createdAt: session.meta.createdAt,
116	  };
117	  const clips: Record<string, (typeof session.clips)[number]> = {};
118	  for (const clip of session.clips) {
119	    clips[clip.id] = clip;
120	  }
121	
122	  useDawStore.setState({
123	    bpm: session.transport.bpm,
124	    loopEnabled: session.transport.loopEnabled,
125	    loopStart: session.transport.loopStart,
126	    loopEnd: session.transport.loopEnd,
127	    tracks: session.tracks,
128	    clips,
129	    masterVolume: session.mixer.masterVolume,
130	  });
131	
132	  // Restore effects state (always clear first to avoid stale ghost inserts)
133	  const trackEffects: Record<
134	    string,
135	    readonly {
136	      id: string;
137	      typeId: string;
138	      bypassed: boolean;
139	      params: Record<string, number>;
140	    }[]
141	  > = {};
142	  if (session.effects) {
143	    for (const entry of session.effects) {
144	      trackEffects[entry.trackId] = entry.slots;
145	    }
146	  }
147	  useEffectsStore.setState({ trackEffects });
148	
149	  // Restore modulation state (Zod already validated source/destination as enums)
150	  const matrices: ModulationStore["matrices"] = {};
151	  let maxRouteNum = 0;
152	  if (session.modulation) {
153	    for (const [trackId, routes] of Object.entries(session.modulation)) {
154	      // Enforce MAX_MOD_ROUTES on load (addRoute guard is bypassed by setState)
155	      const clamped = routes.slice(0, MAX_MOD_ROUTES);
156	      matrices[trackId] = { routes: clamped };
157	      // Track highest route counter to avoid ID collisions
158	      for (const r of clamped) {
159	        const match = /^mod-(\d+)$/.exec(r.id);
160	        if (match) {
161	          maxRouteNum = Math.max(maxRouteNum, Number(match[1]));
162	        }
163	      }
164	    }
165	  }
166	  if (maxRouteNum > 0) {
167	    _seedRouteCounter(maxRouteNum);
168	  }
169	  useModulationStore.setState({ matrices });
170	
171	  // Restore arpeggiator state
172	  const arps: ArpeggiatorStore["arps"] = {};
173	  if (session.arpeggiator) {
174	    for (const entry of session.arpeggiator) {
175	      arps[entry.trackId] = { trackId: entry.trackId, params: entry.params };
176	    }
177	  }
178	  useArpeggiatorStore.setState({ arps });
179	}
