181	type SessionPersistenceResult = {
182	  saving: boolean;
183	  dirty: boolean;
184	  saveNow: () => Promise<void>;
185	  recoveryWarnings: string[];
186	};
187	
188	export function useSessionPersistence(
189	  storage: SessionStorage,
190	): SessionPersistenceResult {
191	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
192	  const [saving, setSaving] = useState(false);
193	  const loadedRef = useRef(false);
194	
195	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
196	
197	  const autoSave = useMemo(
198	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
199	    [saveQueue],
200	  );
201	
202	  // Load session from storage on mount (draft-first for crash safety)
203	  useEffect(() => {
204	    if (loadedRef.current) return;
205	    loadedRef.current = true;
206	
207	    void (async (): Promise<void> => {
208	      // Check draft first — a crash between putDraft and putCurrent
209	      // means the draft is the most recent write attempt
210	      const draft = await storage.getDraft();
211	      const raw = draft ?? (await storage.getCurrent());
212	      if (raw !== undefined) {
213	        const result = recoverSession(raw);
214	        hydrateStore(result.session);
215	        if (draft !== undefined) {
216	          result.warnings.push(
217	            "Recovered from unsaved draft (possible crash recovery)",
218	          );
219	        }
220	        if (result.warnings.length > 0) {
221	          setRecoveryWarnings(result.warnings);
222	        }
223	      }
224	    })();
225	  }, [storage]);
226	
227	  // Start auto-save and subscribe to store changes
228	  useEffect(() => {
229	    autoSave.start();
230	
231	    const unsubDaw = useDawStore.subscribe(() => {
232	      autoSave.notifyChange();
233	    });
234	    const unsubEffects = useEffectsStore.subscribe(() => {
235	      autoSave.notifyChange();
236	    });
237	    const unsubMod = useModulationStore.subscribe(() => {
238	      autoSave.notifyChange();
239	    });
240	    const unsubArp = useArpeggiatorStore.subscribe(() => {
241	      autoSave.notifyChange();
242	    });
243	
244	    return () => {
245	      autoSave.stop();
246	      unsubDaw();
247	      unsubEffects();
248	      unsubMod();
249	      unsubArp();
250	    };
251	  }, [autoSave]);
252	
253	  const saveNow = useCallback(async (): Promise<void> => {
254	    setSaving(true);
255	    await autoSave.saveNow();
256	    await saveQueue.flush();
257	    setSaving(false);
258	  }, [autoSave, saveQueue]);
259	
260	  return {
261	    saving,
262	    dirty: autoSave.dirty,
263	    saveNow,
264	    recoveryWarnings,
265	  };
266	}
