14	
15	export class AddTrackCommand implements UndoCommand {
16	  readonly type = "add-track";
17	
18	  constructor(
19	    private readonly track: TrackModel,
20	    private readonly index?: number,
21	  ) {}
22	
23	  execute(): void {
24	    getStore().addTrack(this.track, this.index);
25	    useArpeggiatorStore.getState().initArp(this.track.id);
26	  }
27	
28	  undo(): void {
29	    useArpeggiatorStore.getState().removeArp(this.track.id);
30	    getStore().removeTrack(this.track.id);
31	  }
32	
33	  serialize(): Record<string, unknown> {
34	    return { track: this.track, index: this.index };
35	  }
36	}
