38	export class RemoveTrackCommand implements UndoCommand {
39	  readonly type = "remove-track";
40	
41	  private savedTrack: TrackModel | undefined;
42	  private savedClips: readonly ClipModel[] = [];
43	  private savedIndex = -1;
44	  private savedArpParams: ArpParams | undefined;
45	
46	  constructor(private readonly trackId: string) {}
47	
48	  execute(): void {
49	    const state = getStore();
50	    this.savedIndex = state.tracks.findIndex((t) => t.id === this.trackId);
51	    this.savedTrack = state.tracks.find((t) => t.id === this.trackId);
52	
53	    if (this.savedTrack) {
54	      this.savedClips = this.savedTrack.clipIds
55	        .map((cid) => state.clips[cid])
56	        .filter((c): c is ClipModel => c !== undefined);
57	    }
58	
59	    this.savedArpParams = useArpeggiatorStore
60	      .getState()
61	      .getParams(this.trackId);
62	    useArpeggiatorStore.getState().removeArp(this.trackId);
63	    state.removeTrack(this.trackId);
64	  }
65	
66	  undo(): void {
67	    if (this.savedTrack === undefined) return;
68	
69	    // Re-add the track at its original position (without clips first)
70	    const trackWithoutClips: TrackModel = { ...this.savedTrack, clipIds: [] };
71	    getStore().addTrack(trackWithoutClips, this.savedIndex);
72	    useArpeggiatorStore.getState().initArp(this.savedTrack.id);
73	    if (this.savedArpParams) {
74	      useArpeggiatorStore
75	        .getState()
76	        .setParams(this.savedTrack.id, this.savedArpParams);
77	    }
78	
79	    // Re-add all clips (addClip also wires up clipIds)
80	    for (const clip of this.savedClips) {
81	      getStore().addClip(clip);
82	    }
83	  }
84	
85	  serialize(): Record<string, unknown> {
86	    return { trackId: this.trackId };
87	  }
88	}
