94	export class UpdateTrackCommand implements UndoCommand {
95	  readonly type = "update-track";
96	
97	  private oldPatch: Partial<Omit<TrackModel, "id">> | undefined;
98	
99	  constructor(
100	    private readonly trackId: string,
101	    private readonly newPatch: Partial<Omit<TrackModel, "id">>,
102	  ) {}
103	
104	  execute(): void {
105	    const track = getStore().tracks.find((t) => t.id === this.trackId);
106	    if (track === undefined) return;
107	
108	    // Capture old values for only the keys being changed
109	    const old: Record<string, unknown> = {};
110	    for (const key of Object.keys(this.newPatch)) {
111	      old[key] = track[key as keyof TrackModel];
112	    }
113	    this.oldPatch = old as Partial<Omit<TrackModel, "id">>;
114	
115	    getStore().updateTrack(this.trackId, this.newPatch);
116	  }
117	
118	  undo(): void {
119	    if (this.oldPatch === undefined) return;
120	    getStore().updateTrack(this.trackId, this.oldPatch);
121	  }
122	
123	  serialize(): Record<string, unknown> {
124	    return {
125	      trackId: this.trackId,
126	      newPatch: this.newPatch,
127	      oldPatch: this.oldPatch,
128	    };
129	  }
130	}
