254	export class SplitClipCommand implements UndoCommand {
255	  readonly type = "split-clip";
256	
257	  private originalClip: ClipModel | undefined;
258	  private generatedRightId: string | undefined;
259	
260	  constructor(
261	    private readonly clipId: string,
262	    private readonly atTime: number,
263	  ) {}
264	
265	  rightClipId(): string | undefined {
266	    return this.generatedRightId;
267	  }
268	
269	  execute(): void {
270	    // Capture full original clip before split
271	    this.originalClip = getStore().clips[this.clipId];
272	    // Pass stored ID on redo to keep clip references deterministic
273	    this.generatedRightId = getStore().splitClip(
274	      this.clipId,
275	      this.atTime,
276	      this.generatedRightId,
277	    );
278	  }
