280	  undo(): void {
281	    if (this.originalClip === undefined) return;
282	
283	    // Remove the right clip created by split
284	    if (this.generatedRightId !== undefined) {
285	      getStore().removeClip(this.generatedRightId);
286	    }
287	
288	    // Restore original clip state (splitClip mutated the left clip in-place)
289	    useDawStore.setState((state) => ({
290	      clips: { ...state.clips, [this.clipId]: this.originalClip as ClipModel },
291	    }));
292	  }
293	
294	  serialize(): Record<string, unknown> {
295	    return {
296	      clipId: this.clipId,
297	      atTime: this.atTime,
298	      rightClipId: this.generatedRightId,
299	      originalClip: this.originalClip,
300	    };
301	  }
302	}
