320	    this.savedClip = getStore().clips[this.clipId];
321	    getStore().trimClip(this.clipId, this.newStart, this.newEnd);
322	  }
323	
324	  undo(): void {
325	    if (this.savedClip === undefined) return;
326	    useDawStore.setState((state) => ({
327	      clips: { ...state.clips, [this.clipId]: this.savedClip as ClipModel },
328	    }));
329	  }
330	
331	  serialize(): Record<string, unknown> {
332	    return {
333	      clipId: this.clipId,
334	      newStart: this.newStart,
335	      newEnd: this.newEnd,
336	    };
337	  }
338	}
