341	// DuplicateClipCommand
342	// ---------------------------------------------------------------------------
343	
344	export class DuplicateClipCommand implements UndoCommand {
345	  readonly type = "duplicate-clip";
346	
347	  private generatedId: string | undefined;
348	
349	  constructor(private readonly clipId: string) {}
350	
351	  duplicatedClipId(): string | undefined {
352	    return this.generatedId;
353	  }
354	
355	  execute(): void {
356	    // Pass stored ID on redo to keep clip references deterministic
357	    this.generatedId = getStore().duplicateClip(this.clipId, this.generatedId);
358	  }
359	
360	  undo(): void {
361	    if (this.generatedId === undefined) return;
362	    getStore().removeClip(this.generatedId);
363	  }
364	
365	  serialize(): Record<string, unknown> {
366	    return { clipId: this.clipId, duplicatedId: this.generatedId };
367	  }
368	}
