import {
  sessionSchema,
  metaSectionSchema,
  transportSectionSchema,
  mixerSectionSchema,
  createDefaultSession,
  SESSION_VERSION,
  type SessionSchema,
} from "./session-schema";
import { z } from "zod/v4";
import { trackSchema, clipSchema } from "@state/track/index";

export type RecoveryResult = {
  session: SessionSchema;
  warnings: string[];
};

export function recoverSession(raw: string): RecoveryResult {
  const warnings: string[] = [];
  const defaults = createDefaultSession();

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return {
      session: defaults,
      warnings: ["Malformed JSON - using default session"],
    };
  }

